// Helper types for the proxy
type tProxyReq = (isWrite: bool, key: int, value: int, caller: machine, podId: int);
type tInFlight = (isWrite: bool, caller: machine, podId: int);
type tWriteItem = (client: machine, value: int);

// StorageProxy models a network proxy with a request queue and nondeterministic forwarding/holding.
machine StorageProxy {
    var db: machine;
    var q: seq[tProxyReq];
    var inFlight: map[int, tInFlight];

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            q = default(seq[tProxyReq]);
            inFlight = default(map[int, tInFlight]);
            goto Run;
        }
    }

    state Run {
        // Enqueue read from callers; record and maybe service one request.
        on eStorageRead do (req: (caller: machine, key: int, podId: int)) {
            var r: tProxyReq;
            r = (isWrite = false, key = req.key, value = 0, caller = req.caller, podId = req.podId);
            q += (sizeof(q), r);
            send this, eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = false, pending = sizeof(q));
            MaybeServiceOne();
        }

        // Enqueue write from callers; record and maybe service one request.
        on eStorageWrite do (req: (caller: machine, key: int, value: int, podId: int)) {
            var r: tProxyReq;
            r = (isWrite = true, key = req.key, value = req.value, caller = req.caller, podId = req.podId);
            q += (sizeof(q), r);
            send this, eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true, pending = sizeof(q));
            MaybeServiceOne();
        }

        // Handle storage read response; deliver to original caller and maybe service one request.
        on eStorageReadResp do (resp: (key: int, value: int)) {
            var meta: tInFlight;
            assert resp.key in inFlight, format("Proxy received read resp for key {0} with no in-flight", resp.key);
            meta = inFlight[resp.key];
            assert !meta.isWrite, format("Proxy response type mismatch on key {0}", resp.key);

            // Announce logical delivery back to caller, then send the response.
            send this, eMonitorProxyResponseDelivered, (key = resp.key, podId = meta.podId, isWrite = false);
            send meta.caller, eStorageReadResp, (key = resp.key, value = resp.value);

            inFlight -= (resp.key);
            MaybeServiceOne();
        }

        // Handle storage write response; deliver to original caller and maybe service one request.
        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var meta: tInFlight;
            assert resp.key in inFlight, format("Proxy received write resp for key {0} with no in-flight", resp.key);
            meta = inFlight[resp.key];
            assert meta.isWrite, format("Proxy response type mismatch on key {0}", resp.key);

            // Announce logical delivery back to caller, then send the response.
            send this, eMonitorProxyResponseDelivered, (key = resp.key, podId = meta.podId, isWrite = true);
            send meta.caller, eStorageWriteResp, (key = resp.key, success = resp.success, value = resp.value);

            inFlight -= (resp.key);
            MaybeServiceOne();
        }
    }

    fun MaybeServiceOne() {
        var pending: int;
        var holdOrSend: int;
        var i: int;
        var idx: int;
        var found: bool;
        var r: tProxyReq;

        pending = sizeof(q);
        if (pending == 0) {
            return;
        }

        // Nondeterministically choose to hold or forward exactly one eligible request.
        holdOrSend = choose(2);
        if (holdOrSend == 0) {
            send this, eMonitorProxyHold, (pending = pending);
            return;
        }

        // Find a request whose key is not already in-flight, to maintain per-key single-flight.
        found = false;
        i = 0;
        while (i < sizeof(q)) {
            if (!(q[i].key in inFlight)) {
                idx = i;
                found = true;
                break;
            }
            i = i + 1;
        }

        if (!found) {
            // All queued requests are blocked by in-flight ones.
            send this, eMonitorProxyHold, (pending = pending);
            return;
        }

        r = q[idx];

        // Announce forward, then send to storage. Store in-flight metadata so we can deliver back.
        send this, eMonitorProxyForward, (key = r.key, podId = r.podId, isWrite = r.isWrite, pending = pending);

        if (r.isWrite) {
            send db, eStorageWrite, (caller = this, key = r.key, value = r.value, podId = r.podId);
        } else {
            send db, eStorageRead, (caller = this, key = r.key, podId = r.podId);
        }

        inFlight[r.key] = (isWrite = r.isWrite, caller = r.caller, podId = r.podId);
        q -= (idx);
    }
}

// CacheNode: thin frontend that deduplicates in-flight reads per key and pipelines writes per key.
// It always touches storage via the proxy for reads to preserve LSI.
machine CacheNode {
    var proxy: machine;
    var podId: int;

    // Read-side: waiters per key and in-flight keys to avoid duplicate proxy round trips.
    var readWaiters: map[int, set[machine]];
    var readInFlight: set[int];

    // Write-side: one in-flight per key plus a FIFO of pending writes per key.
    var writeInFlight: set[int];
    var writeCurrentClient: map[int, machine];
    var writeCurrentValue: map[int, int];
    var writeQueue: map[int, seq[tWriteItem]];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;

            readWaiters = default(map[int, set[machine]]);
            readInFlight = default(set[int]);

            writeInFlight = default(set[int]);
            writeCurrentClient = default(map[int, machine]);
            writeCurrentValue = default(map[int, int]);
            writeQueue = default(map[int, seq[tWriteItem]]);

            goto Ready;
        }
    }

    state Ready {
        // Handle a client read: coalesce concurrent reads on the same key into one proxy round trip.
        on eClientRead do (req: (client: machine, key: int)) {
            var s: set[machine];

            if (req.key in readWaiters) {
                s = readWaiters[req.key];
            } else {
                s = default(set[machine]);
            }
            s += (req.client);
            readWaiters[req.key] = s;

            if (!(req.key in readInFlight)) {
                readInFlight += (req.key);
                // Announce and send one proxy request for this key.
                send this, eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = false);
                send proxy, eStorageRead, (caller = this, key = req.key, podId = podId);
            }
        }

        // Deliver storage read response to all waiting clients for that key.
        on eStorageReadResp do (resp: (key: int, value: int)) {
            var s: set[machine];
            var i: int;

            if (resp.key in readWaiters) {
                s = readWaiters[resp.key];
                i = 0;
                while (i < sizeof(s)) {
                    send s[i], eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                    i = i + 1;
                }
                readWaiters -= (resp.key);
            }
            if (resp.key in readInFlight) {
                readInFlight -= (resp.key);
            }
        }

        // Handle a client write: pipeline writes per key (one in-flight; rest queued).
        on eClientWrite do (req: (client: machine, key: int, value: int)) {
            var q: seq[tWriteItem];
            if (!(req.key in writeInFlight)) {
                // Start immediately.
                writeInFlight += (req.key);
                writeCurrentClient[req.key] = req.client;
                writeCurrentValue[req.key] = req.value;

                send this, eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = true);
                send proxy, eStorageWrite, (caller = this, key = req.key, value = req.value, podId = podId);
            } else {
                // Queue for later.
                if (req.key in writeQueue) {
                    q = writeQueue[req.key];
                } else {
                    q = default(seq[tWriteItem]);
                }
                q += (sizeof(q), (client = req.client, value = req.value));
                writeQueue[req.key] = q;
            }
        }

        // Deliver storage write response to the current writer; start next queued write if any.
        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var cli: machine;
            var q: seq[tWriteItem];
            var next: tWriteItem;

            assert resp.key in writeInFlight, format("Write resp for key {0} but not in-flight", resp.key);
            cli = writeCurrentClient[resp.key];
            send cli, eWriteResp, (key = resp.key, success = resp.success);

            if (resp.key in writeQueue && sizeof(writeQueue[resp.key]) > 0) {
                q = writeQueue[resp.key];
                next = q[0];
                q -= (0);
                if (sizeof(q) == 0) {
                    writeQueue -= (resp.key);
                } else {
                    writeQueue[resp.key] = q;
                }

                writeCurrentClient[resp.key] = next.client;
                writeCurrentValue[resp.key] = next.value;

                send this, eMonitorProxyRequestIssued, (key = resp.key, podId = podId, isWrite = true);
                send proxy, eStorageWrite, (caller = this, key = resp.key, value = next.value, podId = podId);
            } else {
                // No more queued writes for this key.
                writeInFlight -= (resp.key);
                writeCurrentClient -= (resp.key);
                writeCurrentValue -= (resp.key);
                if (resp.key in writeQueue) {
                    writeQueue -= (resp.key);
                }
            }
        }
    }
}
